1	export type Cell = boolean;
2	export type Grid = Cell[][];
3	
4	const SURVIVAL_NEIGHBORS = [2, 3];
5	const REPRODUCTION_NEIGHBORS = 3;
6	
7	const countNeighbors = (grid: Grid, row: number, col: number): number => {
8	  let count = 0;
9	  for (let r = row - 1; r <= row + 1; r++) {
10	    for (let c = col - 1; c <= col + 1; c++) {
11	      if (r === row && c === col) continue;
12	      if (r >= 0 && r < grid.length && c >= 0 && c < grid[0].length && grid[r][c]) {
13	        count++;
14	      }
15	    }
16	  }
17	  return count;
18	};
19	
20	const shouldCellBeAlive = (isAlive: boolean, neighbors: number): boolean =>
21	  (isAlive && SURVIVAL_NEIGHBORS.includes(neighbors)) ||
22	  (!isAlive && neighbors === REPRODUCTION_NEIGHBORS);
23	
24	export function nextGeneration(grid: Grid): Grid {
25	  if (grid.length === 0) {
26	    return [];
27	  }
28	
29	  return grid.map((row, rowIdx) =>
30	    row.map((cell, colIdx) => {
31	      const neighbors = countNeighbors(grid, rowIdx, colIdx);
32	      return shouldCellBeAlive(cell, neighbors);
33	    })
34	  );
35	}
